class Solution {
    private static final int MOD = 1000000007;
    public int numberOfWays(int n, int x) {
        int[] dp = new int[n + 1];
        dp[0] = 1;
        for (int p = 1; p <= n; p++) {
            int pow = (int) Math.pow(p, x);
            if (pow > n) break;
            for (int i = pow; i <= n; i++) {
                dp[i] = (dp[i] + dp[i - pow]) % MOD;
            }
        }
        return dp[n];
    }
}
